**Python Substrate Interface — create query_account.py:**
```python
from substrateinterface import SubstrateInterface

POLKADOT_HUB_RPC = 'INSERT_WS_ENDPOINT'
ACCOUNT_ADDRESS = 'INSERT_ACCOUNT_ADDRESS'
PAS_UNITS = 10_000_000_000

def main():
    substrate = SubstrateInterface(url=POLKADOT_HUB_RPC)
    print('Connected to Polkadot Hub')
    account_info = substrate.query(module='System', storage_function='Account', params=[ACCOUNT_ADDRESS])
    print('Nonce:', account_info.value['nonce'])
    print('Consumers:', account_info.value['consumers'])
    print('Providers:', account_info.value['providers'])
    print('Sufficients:', account_info.value['sufficients'])
    free_balance = account_info.value['data']['free']
    reserved_balance = account_info.value['data']['reserved']
    frozen_balance = account_info.value['data']['frozen']
    print(f'Free Balance: {free_balance} ({free_balance / PAS_UNITS} PAS)')
    print(f'Reserved Balance: {reserved_balance} ({reserved_balance / PAS_UNITS} PAS)')
    print(f'Frozen Balance: {frozen_balance} ({frozen_balance / PAS_UNITS} PAS)')
    total = free_balance + reserved_balance
    print(f'Total Balance: {total} ({total / PAS_UNITS} PAS)')
    substrate.close()

if __name__ == '__main__':
    main()
```
Run with: `python query_account.py`

**Subxt (Rust) — create src/bin/query_account.rs:** (create src/bin/ directory first)
```rust
use std::str::FromStr;
use subxt::utils::AccountId32;
use subxt::{OnlineClient, PolkadotConfig};

#[subxt::subxt(runtime_metadata_path = "polkadot_testnet_metadata.scale")]
pub mod polkadot_testnet {}

const POLKADOT_TESTNET_RPC: &str = "INSERT_WS_ENDPOINT";
const ACCOUNT_ADDRESS: &str = "INSERT_ACCOUNT_ADDRESS";
const PAS_UNITS: u128 = 10_000_000_000;

#[tokio::main(flavor = "current_thread")]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let api = OnlineClient::<PolkadotConfig>::from_url(POLKADOT_TESTNET_RPC).await?;
    let at_block = api.at_current_block().await?;
    println!("Connected to Polkadot Hub");
    let account = AccountId32::from_str(ACCOUNT_ADDRESS)?;
    let account_storage = at_block.storage().entry(polkadot_testnet::storage().system().account())?;
    let info = account_storage.fetch((account,)).await?.decode()?;
    println!("Nonce: {}", info.nonce);
    println!("Consumers: {}", info.consumers);
    println!("Providers: {}", info.providers);
    println!("Sufficients: {}", info.sufficients);
    println!("Free Balance: {} ({} PAS)", info.data.free, info.data.free as f64 / PAS_UNITS as f64);
    println!("Reserved Balance: {} ({} PAS)", info.data.reserved, info.data.reserved as f64 / PAS_UNITS as f64);
    println!("Frozen Balance: {} ({} PAS)", info.data.frozen, info.data.frozen as f64 / PAS_UNITS as f64);
    let total = info.data.free + info.data.reserved;
    println!("Total Balance: {} ({} PAS)", total, total as f64 / PAS_UNITS as f64);
    Ok(())
}
```
Run with: `cargo run --bin query_account`

