Create scripts/compile.js with the following content. This script compiles Storage.sol using solc and saves the ABI to abis/Storage.json and bytecode to artifacts/Storage.bin:

```javascript
import solc from 'solc';
import { readFileSync, writeFileSync, mkdirSync } from 'fs';

const source = readFileSync('contracts/Storage.sol', 'utf8');

const input = JSON.stringify({
  language: 'Solidity',
  sources: { 'Storage.sol': { content: source } },
  settings: { outputSelection: { '*': { '*': ['abi', 'evm.bytecode.object'] } } },
});

const output = JSON.parse(solc.compile(input));
const contract = output.contracts['Storage.sol']['Storage'];

mkdirSync('abis', { recursive: true });
mkdirSync('artifacts', { recursive: true });

writeFileSync('abis/Storage.json', JSON.stringify(contract.abi, null, 2));
writeFileSync('artifacts/Storage.bin', contract.evm.bytecode.object);

console.log('Compilation successful!');
console.log('ABI written to abis/Storage.json');
console.log('Bytecode written to artifacts/Storage.bin');
```

Create scripts/deploy.js with the following content. This script connects to Polkadot Hub TestNet, reads the compiled artifacts, and deploys the Storage contract. The deployed contract address is saved to contract-address.json for use in the interaction step.

```javascript
import { ethers } from 'ethers';
import { readFileSync, writeFileSync } from 'fs';
import 'dotenv/config';

// Connect to Polkadot Hub TestNet
const provider = new ethers.JsonRpcProvider(
  'https://services.polkadothub-rpc.com/testnet',
  { chainId: 420420417, name: 'polkadot-hub-testnet' }
);

// Read compiled artifacts
const abi = JSON.parse(readFileSync('abis/Storage.json', 'utf8'));
const bytecode = '0x' + readFileSync('artifacts/Storage.bin', 'utf8');

async function deploy() {
  console.log('Deploying Storage contract...');

  // Create wallet from mnemonic
  const wallet = ethers.Wallet.fromPhrase(process.env.MNEMONIC).connect(provider);
  console.log(`Deployer address: ${wallet.address}`);

  const balance = await provider.getBalance(wallet.address);
  console.log(`Balance: ${ethers.formatEther(balance)} PAS`);

  // Deploy the contract
  const factory = new ethers.ContractFactory(abi, bytecode, wallet);
  const contract = await factory.deploy();
  await contract.waitForDeployment();

  const address = await contract.getAddress();
  console.log(`Contract deployed to: ${address}`);

  // Save the address for later use
  writeFileSync('contract-address.json', JSON.stringify({ address }, null, 2));
  console.log('Contract address saved to contract-address.json');
}

deploy().catch(console.error);
```

The deployed contract address is saved to contract-address.json — the interaction script reads it from there.

