```typescript
import { createWalletClient, createPublicClient, http } from 'viem';
import { privateKeyToAccount } from 'viem/accounts';
import { polkadotHubTestnet } from './chainConfig';
import { readFileSync, writeFileSync } from 'fs';
import 'dotenv/config';

const abi = JSON.parse(readFileSync('abis/Storage.json', 'utf8'));
const bytecode = ('0x' + readFileSync('artifacts/Storage.bin', 'utf8')) as `0x${string}`;

async function deploy() {
  const account = privateKeyToAccount(process.env.PRIVATE_KEY as `0x${string}`);

  const walletClient = createWalletClient({
    account,
    chain: polkadotHubTestnet,
    transport: http(),
  });

  const publicClient = createPublicClient({
    chain: polkadotHubTestnet,
    transport: http(),
  });

  console.log(`Deployer address: ${account.address}`);

  const hash = await walletClient.deployContract({
    abi,
    bytecode,
  });

  console.log(`Deployment tx hash: ${hash}`);

  const receipt = await publicClient.waitForTransactionReceipt({ hash });
  const contractAddress = receipt.contractAddress;
  console.log(`Contract deployed to: ${contractAddress}`);

  writeFileSync('contract-address.json', JSON.stringify({ address: contractAddress }, null, 2));
  console.log('Contract address saved to contract-address.json');
}

deploy().catch(console.error);
```

