Create src/interact.ts with the following content. This reads the current stored value, sets it to 42, then reads again to verify:

```typescript
import { createWalletClient, createPublicClient, http } from 'viem';
import { privateKeyToAccount } from 'viem/accounts';
import { polkadotHubTestnet } from './chainConfig';
import { readFileSync } from 'fs';
import 'dotenv/config';

const abi = JSON.parse(readFileSync('abis/Storage.json', 'utf8'));
const { address: contractAddress } = JSON.parse(readFileSync('contract-address.json', 'utf8'));

async function interact() {
  const account = privateKeyToAccount(process.env.PRIVATE_KEY as `0x${string}`);

  const walletClient = createWalletClient({
    account,
    chain: polkadotHubTestnet,
    transport: http(),
  });

  const publicClient = createPublicClient({
    chain: polkadotHubTestnet,
    transport: http(),
  });

  // Read current value
  const currentValue = await publicClient.readContract({
    address: contractAddress,
    abi,
    functionName: 'retrieve',
  });
  console.log(`Current stored value: ${currentValue}`);

  // Store a new value (42)
  const hash = await walletClient.writeContract({
    address: contractAddress,
    abi,
    functionName: 'store',
    args: [42n],
  });
  console.log(`Store tx hash: ${hash}`);

  await publicClient.waitForTransactionReceipt({ hash });

  // Read updated value
  const updatedValue = await publicClient.readContract({
    address: contractAddress,
    abi,
    functionName: 'retrieve',
  });
  console.log(`Updated stored value: ${updatedValue}`);
}

interact().catch(console.error);
```

