Create `scripts/compile.js` with the following content:

```js
const solc = require('solc');
const { readFileSync, writeFileSync, mkdirSync, existsSync } = require('fs');
const { basename, join } = require('path');

const ensureDir = (dirPath) => {
  if (!existsSync(dirPath)) { mkdirSync(dirPath, { recursive: true }); }
};

const compileContract = (solidityFilePath, abiDir, artifactsDir) => {
  try {
    const source = readFileSync(solidityFilePath, 'utf8');
    const fileName = basename(solidityFilePath);
    const input = {
      language: 'Solidity',
      sources: { [fileName]: { content: source } },
      settings: { outputSelection: { '*': { '*': ['abi', 'evm.bytecode'] } } },
    };
    console.log(`Compiling contract: ${fileName}...`);
    const output = JSON.parse(solc.compile(JSON.stringify(input)));
    if (output.errors) {
      const errors = output.errors.filter(e => e.severity === 'error');
      if (errors.length > 0) { errors.forEach(err => console.error(err.formattedMessage)); return; }
    }
    ensureDir(abiDir);
    ensureDir(artifactsDir);
    for (const [, contracts] of Object.entries(output.contracts)) {
      for (const [contractName, contract] of Object.entries(contracts)) {
        const abiPath = join(abiDir, `${contractName}.json`);
        writeFileSync(abiPath, JSON.stringify(contract.abi, null, 2));
        console.log(`ABI saved to ${abiPath}`);
        const binPath = join(artifactsDir, `${contractName}.bin`);
        writeFileSync(binPath, contract.evm.bytecode.object);
        console.log(`Bytecode saved to ${binPath}`);
      }
    }
  } catch (error) {
    console.error('Error compiling contracts:', error);
  }
};

const solidityFilePath = join(__dirname, '../contracts/Storage.sol');
const abiDir = join(__dirname, '../abis');
const artifactsDir = join(__dirname, '../artifacts');

compileContract(solidityFilePath, abiDir, artifactsDir);
