Create `scripts/deploy.js` with the following content. Key change from the docs: private key is loaded from process.env.PRIVATE_KEY via dotenv instead of being hardcoded:

```js
require('dotenv').config();
const { writeFileSync, existsSync, readFileSync } = require('fs');
const { join } = require('path');
const { Web3 } = require('web3');

const scriptsDir = __dirname;
const abisDir = join(__dirname, '../abis');
const artifactsDir = join(__dirname, '../artifacts');

const getAbi = (name) => JSON.parse(readFileSync(join(abisDir, `${name}.json`), 'utf8'));
const getByteCode = (name) => {
  const b = readFileSync(join(artifactsDir, `${name}.bin`), 'utf8').trim();
  return b.startsWith('0x') ? b : `0x${b}`;
};

const deployContract = async (contractName, privateKey, providerConfig) => {
  const web3 = new Web3(providerConfig.rpc);
  const key = privateKey.startsWith('0x') ? privateKey : `0x${privateKey}`;
  const account = web3.eth.accounts.privateKeyToAccount(key);
  web3.eth.accounts.wallet.add(account);
  web3.eth.defaultAccount = account.address;
  const abi = getAbi(contractName);
  const bytecode = getByteCode(contractName);
  const contract = new web3.eth.Contract(abi);
  const deployTx = contract.deploy({ data: bytecode });
  const gas = await deployTx.estimateGas();
  const gasPrice = await web3.eth.getGasPrice();
  console.log(`Gas price: ${web3.utils.fromWei(gasPrice, 'gwei')} gwei`);
  const deployed = await deployTx.send({ from: account.address, gas, gasPrice });
  const address = deployed.options.address;
  console.log(`Contract ${contractName} deployed at: ${address}`);
  const file = join(scriptsDir, 'contract-address.json');
  const addrs = existsSync(file) ? JSON.parse(readFileSync(file, 'utf8')) : {};
  addrs[contractName] = address;
  writeFileSync(file, JSON.stringify(addrs, null, 2), 'utf8');
};

const providerConfig = { rpc: 'https://services.polkadothub-rpc.com/testnet', chainId: 420420417, name: 'polkadotTestNet' };
const privateKey = process.env.PRIVATE_KEY;
if (!privateKey) throw new Error('PRIVATE_KEY not set in .env');
deployContract('Storage', privateKey, providerConfig);
